import java.util.Arrays;
public class ArrayCopy {
    public static void main(String[] args) {
        int[] src = {1, 2, 3, 4, 5};
        int[] copy = Arrays.copyOfRange(src, 1, 4);
        System.out.println(Arrays.toString(copy));
        copy[0] = 99;
        System.out.println(src[1]);  // unchanged
        System.out.println(Arrays.copyOf(src, 3).length);
    }
}
